  1→//! Configuration for Vigil telemetry initialization.
  2→//!
  3→//! Supports construction from explicit values or environment variable overrides.
  4→
  5→use std::env;
  6→
  7→/// OTLP transport protocol.
  8→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, serde::Serialize, serde::Deserialize)]
  9→#[serde(rename_all = "snake_case")]
 10→pub enum OtlpProtocol {
 11→    #[default]
 12→    Grpc,
 13→    Http,
 14→}
 15→
 16→/// Log output format.
 17→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, serde::Serialize, serde::Deserialize)]
 18→#[serde(rename_all = "snake_case")]
 19→pub enum LogFormat {
 20→    #[default]
 21→    Pretty,
 22→    Json,
 23→}
 24→
 25→/// Vigil configuration — controls telemetry pipeline setup.
 26→///
 27→/// When constructed with [`VigConfig::default()`], all fields use sensible defaults.
 28→/// Environment variables override programmatic values when [`VigConfig::from_env()`]
 29→/// or [`VigConfig::with_env_overrides()`] is used.
 30→#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
 31→pub struct VigConfig {
 32→    /// Service identity for OTel resource (e.g. "arcan", "lagod", "autonomicd").
 33→    pub service_name: String,
 34→
 35→    /// OTLP collector endpoint (e.g. "http://localhost:4317").
 36→    /// If `None`, no OTel exporter is configured — Vigil degrades to structured logging only.
 37→    pub otlp_endpoint: Option<String>,
 38→
 39→    /// Transport protocol for OTLP export.
 40→    pub otlp_protocol: OtlpProtocol,
 41→
 42→    /// Additional headers for OTLP export (e.g. Langfuse `Authorization: Basic <base64>`).
 43→    pub otlp_headers: Vec<(String, String)>,
 44→
 45→    /// Log output format.
 46→    pub log_format: LogFormat,
 47→
 48→    /// Trace sampling ratio (0.0 = none, 1.0 = all).
 49→    pub sampling_ratio: f64,
 50→
 51→    /// Whether to capture prompt/completion content in spans (privacy-sensitive).
 52→    pub capture_content: bool,
 53→}
 54→
 55→impl Default for VigConfig {
 56→    fn default() -> Self {
 57→        Self {
 58→            service_name: "vigil".to_string(),
 59→            otlp_endpoint: None,
 60→            otlp_protocol: OtlpProtocol::default(),
 61→            otlp_headers: Vec::new(),
 62→            log_format: LogFormat::default(),
 63→            sampling_ratio: 1.0,
 64→            capture_content: false,
 65→        }
 66→    }
 67→}
 68→
 69→impl VigConfig {
 70→    /// Create a config for a named service with sensible defaults.
 71→    pub fn for_service(name: impl Into<String>) -> Self {
 72→        Self {
 73→            service_name: name.into(),
 74→            ..Default::default()
 75→        }
 76→    }
 77→
 78→    /// Build config purely from environment variables.
 79→    pub fn from_env() -> Self {
 80→        Self::default().with_env_overrides()
 81→    }
 82→
 83→    /// Apply environment variable overrides on top of programmatic values.
 84→    ///
 85→    /// Supported env vars:
 86→    /// - `OTEL_EXPORTER_OTLP_ENDPOINT` → `otlp_endpoint`
 87→    /// - `OTEL_EXPORTER_OTLP_HEADERS` → `otlp_headers` (comma-separated `key=value` pairs)
 88→    /// - `OTEL_SERVICE_NAME` → `service_name`
 89→    /// - `VIGIL_LOG_FORMAT` → `log_format` ("json" or "pretty")
 90→    /// - `VIGIL_CAPTURE_CONTENT` → `capture_content` ("true" or "1")
 91→    /// - `VIGIL_SAMPLING_RATIO` → `sampling_ratio` (float 0.0..=1.0)
 92→    pub fn with_env_overrides(mut self) -> Self {
 93→        if let Ok(endpoint) = env::var("OTEL_EXPORTER_OTLP_ENDPOINT") {
 94→            if !endpoint.is_empty() {
 95→                self.otlp_endpoint = Some(endpoint);
 96→            }
 97→        }
 98→
 99→        if let Ok(headers_str) = env::var("OTEL_EXPORTER_OTLP_HEADERS") {
100→            self.otlp_headers = parse_headers(&headers_str);
101→        }
102→
103→        if let Ok(name) = env::var("OTEL_SERVICE_NAME") {
104→            if !name.is_empty() {
105→                self.service_name = name;
106→            }
107→        }
108→
109→        if let Ok(fmt) = env::var("VIGIL_LOG_FORMAT") {
110→            match fmt.to_lowercase().as_str() {
111→                "json" => self.log_format = LogFormat::Json,
112→                "pretty" => self.log_format = LogFormat::Pretty,
113→                _ => {} // ignore unknown values
114→            }
115→        }
116→
117→        if let Ok(capture) = env::var("VIGIL_CAPTURE_CONTENT") {
118→            self.capture_content = matches!(capture.as_str(), "true" | "1" | "yes");
119→        }
120→
121→        if let Ok(ratio) = env::var("VIGIL_SAMPLING_RATIO") {
122→            if let Ok(r) = ratio.parse::<f64>() {
123→                self.sampling_ratio = r.clamp(0.0, 1.0);
124→            }
125→        }
126→
127→        self
128→    }
129→}
130→
131→/// Parse `key=value,key2=value2` header strings into pairs.
132→fn parse_headers(s: &str) -> Vec<(String, String)> {
133→    s.split(',')
134→        .filter_map(|pair| {
135→            let pair = pair.trim();
136→            if pair.is_empty() {
137→                return None;
138→            }
139→            let mut parts = pair.splitn(2, '=');
140→            let key = parts.next()?.trim().to_string();
141→            let value = parts.next()?.trim().to_string();
142→            if key.is_empty() {
143→                return None;
144→            }
145→            Some((key, value))
146→        })
147→        .collect()
148→}
149→
150→#[cfg(test)]
151→mod tests {
152→    use super::*;
153→
154→    #[test]
155→    fn default_config_has_no_endpoint() {
156→        let cfg = VigConfig::default();
157→        assert!(cfg.otlp_endpoint.is_none());
158→        assert_eq!(cfg.sampling_ratio, 1.0);
159→        assert!(!cfg.capture_content);
160→        assert_eq!(cfg.log_format, LogFormat::Pretty);
161→        assert_eq!(cfg.otlp_protocol, OtlpProtocol::Grpc);
162→    }
163→
164→    #[test]
165→    fn for_service_sets_name() {
166→        let cfg = VigConfig::for_service("arcan");
167→        assert_eq!(cfg.service_name, "arcan");
168→    }
169→
170→    #[test]
171→    fn parse_headers_works() {
172→        let result = parse_headers("Authorization=Basic abc123,X-Custom=value");
173→        assert_eq!(result.len(), 2);
174→        assert_eq!(
175→            result[0],
176→            ("Authorization".to_string(), "Basic abc123".to_string())
177→        );
178→        assert_eq!(result[1], ("X-Custom".to_string(), "value".to_string()));
179→    }
