181→    #[test]
182→    fn parse_headers_handles_empty() {
183→        assert!(parse_headers("").is_empty());
184→        assert!(parse_headers("  ").is_empty());
185→        assert!(parse_headers(",,,").is_empty());
186→    }
187→
188→    #[test]
189→    fn parse_headers_handles_missing_value() {
190→        let result = parse_headers("key_only");
191→        assert!(result.is_empty());
192→    }
193→
194→    // Env var tests are #[ignore] because env vars are process-global and
195→    // race under parallel test execution. Run with:
196→    //   cargo test -- --ignored --test-threads=1
197→    #[test]
198→    #[ignore]
199→    fn env_overrides_all_fields() {
200→        // SAFETY: Rust 2024 requires unsafe for set_var/remove_var.
201→        unsafe {
202→            env::set_var("OTEL_EXPORTER_OTLP_ENDPOINT", "http://test:4317");
203→            env::set_var("OTEL_SERVICE_NAME", "vigil-test-svc");
204→            env::set_var("VIGIL_LOG_FORMAT", "json");
205→            env::set_var("VIGIL_CAPTURE_CONTENT", "true");
206→            env::set_var("VIGIL_SAMPLING_RATIO", "0.5");
207→        }
208→
209→        let cfg = VigConfig::default().with_env_overrides();
210→        assert_eq!(cfg.otlp_endpoint.as_deref(), Some("http://test:4317"));
