                tokio::task::spawn_blocking(move || Self::append_batch_blocking(&db, events))
                    .await
                    .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
                    ?;

            for notification in notifications {
                let _ = notify_tx.send(notification);
            }
            Ok(last_seq)
        })
    }

    fn append_batch(
        &self,
        events: Vec<EventEnvelope>,
    ) -> std::pin::Pin<Box<dyn std::future::Future<Output = LagoResult<SeqNo>> + Send + '_>> {
        let db = Arc::clone(&self.db);
        let notify_tx = self.notify_tx.clone();
        Box::pin(async move {
            if events.is_empty() {
                return Ok(0);
            }
            let (last_seq, notifications) =
                tokio::task::spawn_blocking(move || Self::append_batch_blocking(&db, events))
                    .await
                    .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
                    ?;

            for notification in notifications {
                let _ = notify_tx.send(notification);
            }
            Ok(last_seq)
        })
    }

    fn read(
        &self,
        query: EventQuery,
    ) -> std::pin::Pin<
        Box<dyn std::future::Future<Output = LagoResult<Vec<EventEnvelope>>> + Send + '_>,
    > {
        let db = Arc::clone(&self.db);
        Box::pin(async move {
            tokio::task::spawn_blocking(move || Self::read_blocking(&db, query))
                .await
                .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
        })
    }

    fn get_event(
        &self,
        event_id: &EventId,
    ) -> std::pin::Pin<
        Box<dyn std::future::Future<Output = LagoResult<Option<EventEnvelope>>> + Send + '_>,
    > {
        let id_str = event_id.as_str().to_string();
        let db = Arc::clone(&self.db);
        Box::pin(async move {
            tokio::task::spawn_blocking(move || Self::get_event_blocking(&db, &id_str))
                .await
                .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
        })
    }

    fn head_seq(
        &self,
        session_id: &SessionId,
        branch_id: &BranchId,
    ) -> std::pin::Pin<Box<dyn std::future::Future<Output = LagoResult<SeqNo>> + Send + '_>> {
        let db = Arc::clone(&self.db);
        let sid = session_id.as_str().to_string();
        let bid = branch_id.as_str().to_string();
        Box::pin(async move {
            tokio::task::spawn_blocking(move || Self::head_seq_blocking(&db, &sid, &bid))
                .await
                .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
        })
    }

    fn stream(
        &self,
        session_id: SessionId,
        branch_id: BranchId,
        after_seq: SeqNo,
    ) -> std::pin::Pin<Box<dyn std::future::Future<Output = LagoResult<EventStream>> + Send + '_>>
    {
        let db = Arc::clone(&self.db);
        let rx = self.notify_tx.subscribe();
        Box::pin(async move {
            let tail = EventTailStream::new(db, rx, session_id, branch_id, after_seq);
            Ok(Box::pin(tail) as EventStream)
        })
    }

    fn put_session(
        &self,
        session: Session,
    ) -> std::pin::Pin<Box<dyn std::future::Future<Output = LagoResult<()>> + Send + '_>> {
        let db = Arc::clone(&self.db);
        Box::pin(async move {
            tokio::task::spawn_blocking(move || Self::put_session_blocking(&db, session))
                .await
                .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
        })
    }

    fn get_session(
        &self,
        session_id: &SessionId,
    ) -> std::pin::Pin<Box<dyn std::future::Future<Output = LagoResult<Option<Session>>> + Send + '_>>
    {
        let db = Arc::clone(&self.db);
        let sid = session_id.as_str().to_string();
        Box::pin(async move {
            tokio::task::spawn_blocking(move || Self::get_session_blocking(&db, &sid))
                .await
                .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
        })
    }
}
```

**Critical Pattern**: All redb operations are synchronous and run on `tokio::task::spawn_blocking`. The Journal trait uses `BoxFuture<'_, Output>` for dyn-trait compatibility.

### 3. Blob Store - Function Signatures

**File**: `/tmp/lago/crates/lago-store/src/blob.rs`

Content-addressed blob store with automatic compression and git-like object layout:

```rust
pub struct BlobStore {
    root: PathBuf,
}

impl BlobStore {
    /// Open (or create) a blob store rooted at the given directory.
    pub fn open(path: impl AsRef<Path>) -> LagoResult<Self> {
        let root = path.as_ref().to_path_buf();
        fs::create_dir_all(&root)?;
        debug!(path = %root.display(), "blob store opened");
        Ok(Self { root })
    }

    /// Store data and return its content hash.
    /// If a blob with the same hash already exists on disk, the write is skipped.
    pub fn put(&self, data: &[u8]) -> LagoResult<BlobHash> {
        let hash = hash::hash_bytes(data);

        if self.exists(&hash) {
            trace!(hash = %hash, "blob already exists, skipping write");
            return Ok(hash);
        }

        let blob_path = self.blob_path(&hash);
        if let Some(parent) = blob_path.parent() {
            fs::create_dir_all(parent)?;
        }

        let compressed = compress::compress(data)?;

        // Write atomically via a temp file
        let tmp_path = blob_path.with_extension("zst.tmp");
        fs::write(&tmp_path, &compressed)?;
        fs::rename(&tmp_path, &blob_path)?;

        debug!(hash = %hash, size = data.len(), compressed = compressed.len(), "blob stored");
        Ok(hash)
    }

    /// Retrieve the decompressed contents of a blob by its hash.
    pub fn get(&self, hash: &BlobHash) -> LagoResult<Vec<u8>> {
        let blob_path = self.blob_path(hash);

        if !blob_path.exists() {
            return Err(LagoError::BlobNotFound(hash.to_string()));
        }

        let compressed = fs::read(&blob_path)?;
        let data = compress::decompress(&compressed)?;

        trace!(hash = %hash, size = data.len(), "blob retrieved");
        Ok(data)
    }

    /// Check whether a blob with the given hash exists on disk.
    pub fn exists(&self, hash: &BlobHash) -> bool {
        self.blob_path(hash).exists()
    }

    /// Delete a blob from disk. Returns an error if the blob does not exist.
    pub fn delete(&self, hash: &BlobHash) -> LagoResult<()> {
        let blob_path = self.blob_path(hash);

        if !blob_path.exists() {
            return Err(LagoError::BlobNotFound(hash.to_string()));
        }

        fs::remove_file(&blob_path)?;
        debug!(hash = %hash, "blob deleted");

        // Try to remove the shard directory if empty (best-effort)
        if let Some(parent) = blob_path.parent() {
            let _ = fs::remove_dir(parent);
        }

        Ok(())
    }

    /// Compute the on-disk path for a given blob hash.
    /// Layout: `{root}/{hash[0..2]}/{hash[2..]}.zst`
    fn blob_path(&self, hash: &BlobHash) -> PathBuf {
        let hex = hash.as_str();
        let (prefix, rest) = hex.split_at(2);
        self.root.join(prefix).join(format!("{rest}.zst"))
    }
}
```

### 4. Hash & Compression Utilities

**File**: `/tmp/lago/crates/lago-store/src/hash.rs`

```rust
pub fn hash_bytes(data: &[u8]) -> BlobHash {
    let mut hasher = Sha256::new();
    hasher.update(data);
    let result = hasher.finalize();
    BlobHash::from_hex(hex::encode(result))
}

pub fn verify_hash(data: &[u8], expected: &BlobHash) -> bool {
    let actual = hash_bytes(data);
    actual == *expected
}
